var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"으윽… 머리야.","JPN":"ううっ……頭痛い。","ENG":"Ugh... my head.","TWN":"呃……頭好暈……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"능력을 두 번이나 썼더니 어지러워.","JPN":"能力を2回も使ったからクラクラする。","ENG":"I feel dizzy from using my ability twice.","TWN":"因為兩次使用能力，頭好暈啊。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"너처럼 능력이 미숙한 애들은 흔적이 남거든.","JPN":"あなたのように能力が未熟な子は痕跡が残るの。","ENG":"Amateurs like you with unrefined abilities leave traces.","TWN":"像你這種能力尚不成熟的人，總是會留下些蛛絲馬跡的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"분해…….","JPN":"悔しい……","ENG":"I'm so angry...","TWN":"可惡……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"이 능력을 맘대로 쓸 수만 있었어도 은행을 터는 것쯤은 간단했을 텐데.","JPN":"この能力をちゃんと使いこなせたら銀行からお金を盗むことも簡単にできるはずなのに。","ENG":"If I could use this ability freely, robbing a bank would have been easy.","TWN":"如果能自由掌控這股力量，哪怕搶劫銀行也能輕而易舉吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"그럼 헤일리한테 필요한 약도 잔뜩 살 수 있고…","JPN":"そしたらヘイリーが必要な薬もたくさん買えるし……","ENG":"Then, I could buy all the medicine Hailey needs...","TWN":"那樣的話，我就能給海莉買足夠的藥……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"넌 지금 밑 빠진 독에 물을 붓고 있는 거라고. 네 인생을 망쳐가면서까지.","JPN":"あなたは今意味のないことをしているのよ。自分の人生をダメにしてまで。","ENG":"Right now, you're just trying to fill a bottomless pit, ruining your life in the process.","TWN":"你就像拼命往破碎的罐子裡注水的人，甚至不惜為此毀掉你的人生。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"그게 뭐가 잘못된 건데…","JPN":"それの何が悪い……","ENG":"What's wrong with that...?","TWN":"這又有什麼錯？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"사람을 살리려는 게 왜 잘못된 거냐고…","JPN":"人を助けたいと思って、何が悪いの……","ENG":"What's wrong with wanting to save people...?","TWN":"想拯救重要的人，到底有什麼錯？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_QM","text":{"KOREA":"…찾았다. 카운터.","JPN":"……見つけた。カウンター。","ENG":"...Found one. A Counter.","TWN":"……找到了，制裁者。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"누구야?!","JPN":"誰！？","ENG":"Who's there?!","TWN":"誰？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"너도 날 붙잡으러 온 거야?!","JPN":"あんたも私を捕まえにきたの！？","ENG":"Did you also come to catch me?!","TWN":"你也是來抓我的嗎？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_QM","text":{"KOREA":"널 찾는 인간… 더 있어?","JPN":"あなたを探す人間……もっといる？","ENG":"Are there more people... looking for you?","TWN":"難道除了我，還有人找你？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_QM","text":{"KOREA":"그럴 것 같아. 너, 맛있어보여.","JPN":"そう見える。あなた、美味しそう。","ENG":"Makes sense. You, look tasty.","TWN":"也對，畢竟你……看起來很好吃。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"콜록 콜록…","JPN":"ゲホゲホ……","ENG":"*Cough* *Cough*","TWN":"咳咳……咳咳……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이거… 갖고 있으세요.","JPN":"これ……どうぞ。","ENG":"Here... please take this.","TWN":"這個……請收好。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"이건… 꽃향기…?","JPN":"これは……花の香り……？","ENG":"I smell... flowers...?","TWN":"這是……花香？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"아아, 꽃반지군요. 그립네요.","JPN":"ああ、花の指輪ですね。懐かしい。","ENG":"Oh, it's a flower ring. How nostalgic.","TWN":"啊，是花戒指啊，真令人懷念呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"옛날엔 들꽃을 꺾어서 머리띠도 만들곤 했는데. 이제 들판도, 꽃도 흔치 않거든요.","JPN":"昔は野花を摘み髪飾りも作ったわ。今は野原も、花もめったに見れなくりましたけど。","ENG":"Back in the day, I used to pick wildflowers and make headbands. But now, that kind of thing is rare.","TWN":"以前還會採集野花編成花環戴在頭上呢，現在已經很少有人這麼做了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"많이 아픈 건가요?","JPN":"体調がだいぶ悪いんですよね？","ENG":"Are you in a lot of pain?","TWN":"很痛吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"흔한 침식증후군입니다. 어리석은 사람이 욕심까지 많으면 걸리는 병이죠.","JPN":"よくある侵食症候群です。愚かな人が欲張るとかかる病なんです。","ENG":"It's a common case of Corruption Syndrome. It's an illness that people who are both foolish and greedy tend to get.","TWN":"很常見的侵蝕症候群罷了。愚蠢的人如果欲望過多，就會染上這種病。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"제 스스로 침식지대에 발을 들여 얻은 것이니… 자업자득이에요.","JPN":"自ら侵食地帯に入ったせいでかかったので……自業自得です。","ENG":"I got it by stepping into the Corrupted Area on my own will... It's my own fault.","TWN":"是我自己踏入侵蝕區才感染的……都是我自作自受。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"거기 들어간 걸 후회했나요?","JPN":"その地に入ったことを後悔していますか？","ENG":"Do you regret stepping into that area?","TWN":"踏入那片土地，你後悔嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"후후, 글쎄요.","JPN":"ふふ、どうでしょう。","ENG":"Haha, well, I'm not sure.","TWN":"呵呵……怎麼說呢？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"고양이를 찾으려고 침식재난이 있었던 곳에 멋대로 들어갔어요. 가족 없는 저에겐 유일한 친구라서… 그땐 정말로 절박했거든요.","JPN":"猫を探すために侵食災害があった場所に入ったんです。ホームレスの私にとっては唯一の家族でしたから……その時は本当に必死でした。","ENG":"I went into the area where a Corruption disaster occurred to find my cat. For someone like me, a drifter with no family, the cat was my only family... I was truly desperate at that time.","TWN":"當初我是為了尋找我的貓才進入了發生過侵蝕災害的地方。對我這種無家可歸的人來說，那是我唯一的家人……當時真的很絕望呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"고양이는 결국 못 찾았지만, 다른 울음소릴 들었어요. 버려진 유모차에 있던 작은 아기였죠.","JPN":"猫は結局見つかりませんでしたが、別の鳴き声を聞きました。捨てられたベビーカーの中にいる小さい赤子でした。","ENG":"I couldn't find the cat in the end, but I heard another cry. It was a little baby crying in an abandoned stroller.","TWN":"雖然最終也沒能找到那隻貓，但在那裡，我遇到了新的羈絆。在一輛破舊的嬰兒車裡，我發現了正在哭泣的小嬰兒。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그 아기의 이름이 혹시… 애니?","JPN":"その赤子の名前がもしかして……エニー？","ENG":"That baby's name is... Annie?","TWN":"那個孩子的名字……是安妮？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"맞아요. 전 이름 짓는 재주가 없어서, 잃어버린 고양이 이름을 붙였어요.","JPN":"そうです。私は名前をつけるのが下手で、その時なくした猫の名前を付けました。","ENG":"That's right. I'm not good at naming, so I gave her the same name as the cat I lost at that time.","TWN":"是的，我不擅長取名字，所以就給她取了當時走失的貓的名字。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"비록 전 그 애 엄마가 아니지만… 자식이 있다면 이런 심정이었겠죠.","JPN":"私はあの子の実のお母さんではないですが……自分の子がいたら、こんな気持ちだったのでしょう。","ENG":"Although I'm not her mother... I raised her as if she was my own.","TWN":"雖然我不是她的親生媽媽……但我一直把她當成自己的孩子來用心撫養。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"제 침식증후군 같은 건 아무래도 좋을 정도로- 정말 정말 사랑스러운 아이였거든요.","JPN":"私の侵食症候群なんてどうでもいいくらいに……本当に本当に可愛い子でしたから。","ENG":"I loved Annie so much that I really didn't care about my Corruption Syndrome.","TWN":"安妮……是值得我用一生去守護的孩子。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"나 같은 불치병 환자를 버리지 않고 끝까지 노력하는 것만 봐도 얼마나 좋은 애인지 알 수 있죠.","JPN":"私のような不治の病を患う患者も見捨てず最後まで努力する姿を見ても、どんなにいい子なのかわかります。","ENG":"Just watching her tirelessly care for someone like me, despite my incurable disease, shows what a kind person she is.","TWN":"看她如此努力也不願拋棄我這個絕症病人，就足以說明她有多麼善良。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"그렇기 때문에... 그 아이가 자기 손을 더럽히진 않았으면 해요.","JPN":"だから……私のせいであの子が自分の手を汚すことはしないでほしいんです。","ENG":"So... I hope she doesn't get her hands dirty because of me.","TWN":"但是……我不希望她因為我而犯罪。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"길거릴 떠도는 대신 학교에 다니며, 좋은 것만 누리면 좋겠어요.","JPN":"普通の子どものように学校に通いながら、人並みの幸せを感じてほしいんです。","ENG":"I hope she gets to live like children of her age, by going to school and enjoying the good things in life.","TWN":"我更希望她能像其他同齡的孩子一樣，去學校讀書，去享受美好的事物。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"병든 노숙자 주제에… 저도 참 욕심 많은 사람이네요. 그렇죠?","JPN":"病気持ちのホームレスのくせに……私も本当に欲深い。そう思いませんか？","ENG":"For a sick homeless person like me... I really am a greedy person, aren't I?","TWN":"身為一個病入膏肓的流浪漢……我也太貪心了，對吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"애니는 헤일리 씨가 밉다고 했지만, 사실 다 이해하고 있을 거에요.","JPN":"エニーはヘイリーさんが嫌いって言ってたけど、本当は全部わかっているはずです。","ENG":"Annie said she hates you, but I think she understands everything deep down.","TWN":"安妮雖然嘴上說著討厭海莉，但其實她心裡什麼都明白。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그걸 받아들이면 너무 슬프니까… 대신 화를 낼 뿐인 거라 생각해요.","JPN":"それを受け入れたらとても悲しいから……代わりに怒っているだけだと思います。","ENG":"She probably gets angry... because accepting it is too sad.","TWN":"她只是不願接受現實，因為那樣會讓她更痛苦……所以才選擇逃避。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"고맙군요. 그렇게 말해줘서.","JPN":"ありがとうございます。そう言ってくれて。","ENG":"Thank you for saying that.","TWN":"謝謝你能這麼說。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"하지만 그 아이가 나쁜 길로 들어서게 된 건, 그걸 막지 못한 내 탓이에요.","JPN":"でもあの子が悪さをするようになったのは、それを止められなかった私が悪いんです。","ENG":"But the reason she went down a bad path is because I couldn't stop her, which is my fault.","TWN":"但是，讓她誤入歧途的責任……在我。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"그러니 부탁드려요, 경관님.","JPN":"だから、お願いします、お巡りさん。","ENG":"So please, I'm asking you, officer.","TWN":"所以……警官，拜託你了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"그 아이가 꿈을 잃지 않게… 부디 도와주세요.","JPN":"あの子が夢を失わないように……どうか力を貸してやってください。","ENG":"Please help her... pursue her own dream.","TWN":"請引導她找到正確的道路……讓她拯救自己。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"헉… 헉…","JPN":"はっ……はぁ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L24_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"우욱, 매스꺼…","JPN":"うっ、気持ち悪い……","ENG":"Ugh, I don't feel so good...","TWN":"嗚啊，好噁心……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L26_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"…방금 그건 뭐였지?","JPN":"……さっきのあれは何だったの？","ENG":"...What was that just now?","TWN":"……剛剛那是什麼？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"날 찌르려던 그 꼬리… 분명 사람이 아니었어.","JPN":"私を刺そうとしたあの尻尾……絶対人間じゃなかった。","ENG":"Her tail tried to stab me... She definitely isn't human.","TWN":"剛才想刺我的那條尾巴……絕對不是人身上長的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"설마 도시관리국이 대피령을 내린 이유가 그 녀석 때문인가?","JPN":"まさか都市管理局が出した避難令は、あれが原因だったの？","ENG":"Could the City Management have issued the evacuation order because of that creature?","TWN":"難道，城市管理局下達疏散的原因……就是那傢伙？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"돌아가야 돼. 헤일리가 위험할지도 몰라.","JPN":"戻らなきゃ。ヘイリーが危ないかもしれない。","ENG":"I need to go back. Hailey might be in danger.","TWN":"我必須回去，海莉可能有危險。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"그치만 그 경찰들이 아직 지키고 있는 거라면…","JPN":"でも、まだ警察があそこにいたら……","ENG":"But if the police are still guarding that place...","TWN":"但如果那些警察還守在那裡的話……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"윽?!","JPN":"うっ！？","ENG":"Ngh?!","TWN":"呃？！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_LAUGH"},"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_QM","text":{"KOREA":"키히힛- 잡았다아.","JPN":"キヒヒー捕まえたあ。","ENG":"Keeheehee! I caught you!","TWN":"嘻嘻嘻～抓到你了。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_PRIDE"},"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"이… 이거 놔! 괴물아!","JPN":"は……離しなさい！　この化け物！","ENG":"L-let go! You monster!","TWN":"放……放開我！怪物！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_PRIDE"},"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_QM","text":{"KOREA":"사라지는 카운터 좋아. 쫓는 거 재밌어.","JPN":"消えるカウンター、いい。追いかけっこ面白い。","ENG":"I like Counters that disappear. Chasing them is fun.","TWN":"消失的制裁者……真好，追起來還真有趣。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_IDLE"},"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_QM","text":{"KOREA":"…아야-","JPN":"……いたー","ENG":"...Ouch.","TWN":"……哎呀——"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그거 유감이네.","JPN":"それは残念ね。","ENG":"That's a shame.","TWN":"真不巧呢。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L45_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이쪽은 쫓아다니는 일이라면 이제 질색이거든?","JPN":"こっちは追いかけっこはもう大っ嫌いなの。","ENG":"I can't stand chasing after someone!","TWN":"我最討厭玩警察抓小偷的遊戲了！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_QM","text":{"KOREA":"…끈질겨어.","JPN":"……しつこい。","ENG":"...Persistent.","TWN":"……還真是難纏呢。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_QM","text":{"KOREA":"너희도 날 먹고 싶은 거야? 어차피 안 줄 거지만.","JPN":"あなたたちも私を食べたい？　あげないけど。","ENG":"Do you want to eat me too? I won't give myself to you anyway.","TWN":"你們也想吃了我嗎？不過，我可不會讓你們得逞。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_QM","text":{"KOREA":"메-롱-","JPN":"べー","ENG":"Bleh!","TWN":"ㄌㄩㄝ～～"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아오, 저게…!","JPN":"うう、こいつ……！","ENG":"Ugh! Seriously...!","TWN":"可惡，這傢伙……！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어째 말하는 실력이 전보다 능숙해졌네요. 나쁜 방향으로 말이죠.","JPN":"何だか以前より話し方が流暢になりましたね。悪い方向に。","ENG":"She's more skilled at talking now, but in a bad way.","TWN":"話說……對能力的使用倒是比以前更熟練了呢，而且還是朝著不好的方向。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"넌 포위됐어! 해치워주마!","JPN":"あなたは包囲されている！　やっつけてあげるわ！","ENG":"You're surrounded! I'll eliminate you!","TWN":"你已經無路可逃了！受死吧！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MIMIC_CORRUPTED_NULL_QM","face":"UNIT_HATE"}}}}]`);export{e as default};